(window.webpackJsonp=window.webpackJsonp||[]).push([[815],{776:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums1</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums2</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxDotProduct = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums1, nums2</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> len1=nums1.length\\n  <span class=\\"hljs-keyword\\">let</span> len2=nums2.length\\n  <span class=\\"hljs-keyword\\">let</span> dp=<span class=\\"hljs-built_in\\">Array</span>(len1+<span class=\\"hljs-number\\">1</span>).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-built_in\\">Array</span>(len2+<span class=\\"hljs-number\\">1</span>).fill(-<span class=\\"hljs-literal\\">Infinity</span>))\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;len1+<span class=\\"hljs-number\\">1</span>;i++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">1</span>;j&lt;len2+<span class=\\"hljs-number\\">1</span>;j++){\\n      dp[i][j]=<span class=\\"hljs-built_in\\">Math</span>.max(dp[i][j],dp[i<span class=\\"hljs-number\\">-1</span>][j])\\n      dp[i][j]=<span class=\\"hljs-built_in\\">Math</span>.max(dp[i][j],dp[i][j<span class=\\"hljs-number\\">-1</span>])\\n      dp[i][j]=<span class=\\"hljs-built_in\\">Math</span>.max(dp[i][j],dp[i<span class=\\"hljs-number\\">-1</span>][j<span class=\\"hljs-number\\">-1</span>])\\n      dp[i][j]=<span class=\\"hljs-built_in\\">Math</span>.max(dp[i][j],<span class=\\"hljs-built_in\\">Math</span>.max(dp[i<span class=\\"hljs-number\\">-1</span>][j<span class=\\"hljs-number\\">-1</span>],<span class=\\"hljs-number\\">0</span>)+nums1[i<span class=\\"hljs-number\\">-1</span>]*nums2[j<span class=\\"hljs-number\\">-1</span>])\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> dp[len1][len2]\\n  \\n};\\n</code></pre>\\n"],"titleSlug":"max-dot-product-of-two-subsequences","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e24\u4e2a\u6570\u7ec4&nbsp;<code>nums1</code>&nbsp;\u548c&nbsp;<code>nums2</code>&nbsp;\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de <code>nums1</code> \u548c <code>nums2</code> \u4e2d\u4e24\u4e2a\u957f\u5ea6\u76f8\u540c\u7684 <strong>\u975e\u7a7a</strong> \u5b50\u5e8f\u5217\u7684\u6700\u5927\u70b9\u79ef\u3002</p>\\n\\n<p>\u6570\u7ec4\u7684\u975e\u7a7a\u5b50\u5e8f\u5217\u662f\u901a\u8fc7\u5220\u9664\u539f\u6570\u7ec4\u4e2d\u67d0\u4e9b\u5143\u7d20\uff08\u53ef\u80fd\u4e00\u4e2a\u4e5f\u4e0d\u5220\u9664\uff09\u540e\u5269\u4f59\u6570\u5b57\u7ec4\u6210\u7684\u5e8f\u5217\uff0c\u4f46\u4e0d\u80fd\u6539\u53d8\u6570\u5b57\u95f4\u76f8\u5bf9\u987a\u5e8f\u3002\u6bd4\u65b9\u8bf4\uff0c<code>[2,3,5]</code>&nbsp;\u662f&nbsp;<code>[1,2,3,4,5]</code>&nbsp;\u7684\u4e00\u4e2a\u5b50\u5e8f\u5217\u800c&nbsp;<code>[1,5,3]</code>&nbsp;\u4e0d\u662f\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums1 = [2,1,-2,5], nums2 = [3,0,-6]\\n<strong>\u8f93\u51fa\uff1a</strong>18\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece nums1 \u4e2d\u5f97\u5230\u5b50\u5e8f\u5217 [2,-2] \uff0c\u4ece nums2 \u4e2d\u5f97\u5230\u5b50\u5e8f\u5217 [3,-6] \u3002\\n\u5b83\u4eec\u7684\u70b9\u79ef\u4e3a (2*3 + (-2)*(-6)) = 18 \u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums1 = [3,-2], nums2 = [2,-6,7]\\n<strong>\u8f93\u51fa\uff1a</strong>21\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece nums1 \u4e2d\u5f97\u5230\u5b50\u5e8f\u5217 [3] \uff0c\u4ece nums2 \u4e2d\u5f97\u5230\u5b50\u5e8f\u5217 [7] \u3002\\n\u5b83\u4eec\u7684\u70b9\u79ef\u4e3a (3*7) = 21 \u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums1 = [-1,-1], nums2 = [1,1]\\n<strong>\u8f93\u51fa\uff1a</strong>-1\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece nums1 \u4e2d\u5f97\u5230\u5b50\u5e8f\u5217 [-1] \uff0c\u4ece nums2 \u4e2d\u5f97\u5230\u5b50\u5e8f\u5217 [1] \u3002\\n\u5b83\u4eec\u7684\u70b9\u79ef\u4e3a -1 \u3002</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= nums1.length, nums2.length &lt;= 500</code></li>\\n\\t<li><code>-1000 &lt;= nums1[i], nums2[i] &lt;= 100</code></li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u70b9\u79ef\uff1a</strong></p>\\n\\n<pre>\\n\u5b9a\u4e49 <code><strong>a</strong>&nbsp;= [<em>a</em><sub>1</sub>,&nbsp;<em>a</em><sub>2</sub>,&hellip;,&nbsp;<em>a</em><sub><em>n</em></sub>]</code> \u548c<strong> <code>b</code></strong><code>&nbsp;= [<em>b</em><sub>1</sub>,&nbsp;<em>b</em><sub>2</sub>,&hellip;,&nbsp;<em>b</em><sub><em>n</em></sub>]</code> \u7684\u70b9\u79ef\u4e3a\uff1a\\n\\n<img alt=\\"\\\\mathbf{a}\\\\cdot \\\\mathbf{b} = \\\\sum_{i=1}^n a_ib_i = a_1b_1 + a_2b_2 + \\\\cdots + a_nb_n \\" class=\\"tex\\" src=\\"http://upload.wikimedia.org/math/c/3/2/c329bf86e747d74f55ed2e17c36fd83f.png\\" />\\n\\n\u8fd9\u91cc\u7684 <strong>&Sigma;</strong> \u6307\u793a\u603b\u548c\u7b26\u53f7\u3002\\n</pre>\\n","title":"1458. \u4e24\u4e2a\u5b50\u5e8f\u5217\u7684\u6700\u5927\u70b9\u79ef","relatedTags":["\u52a8\u6001\u89c4\u5212"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1458"}')}}]);